import java.util.*;

public class Main {
    public static long countPairsLessThanX(int[] arr, int x) {
        long count = 0;
        int left = 0, right = arr.length - 1;
        while (left < right) {
            if (arr[left] + arr[right] < x) {
                count += (right - left);
                left++;
            } else {
                right--;
            }
        }
        return count;
    }

